57	  // Flatten an array of [a,b,c] triples — the numpy (N,3).tolist() shape that
58	  // real phase geometry ships — into a flat typed array of length 3N. Also
59	  // accepts an already-flat numeric array (length divisible by 3). Returns
60	  // null for empty/malformed/non-finite input: three.js coerces nested arrays
61	  // and bad values to NaN, which renders an invisible mesh and logs
62	  // "Computed radius is NaN", so malformed structures are skipped instead.
63	  function flattenTriples(arr, Ctor) {
64	    if (!Array.isArray(arr) || arr.length === 0) return null;
65	    var out, i, t, v;
66	    if (Array.isArray(arr[0])) {          // nested (N,3) shape
67	      out = new Ctor(arr.length * 3);
68	      for (i = 0; i < arr.length; i++) {
69	        t = arr[i];
70	        if (!Array.isArray(t) || t.length !== 3 ||
71	            !isFinite(t[0]) || !isFinite(t[1]) || !isFinite(t[2])) return null;
72	        out[i * 3] = t[0]; out[i * 3 + 1] = t[1]; out[i * 3 + 2] = t[2];
73	      }
74	      return out;
75	    }
76	    if (arr.length % 3 !== 0) return null; // flat shape
77	    out = new Ctor(arr.length);
78	    for (i = 0; i < arr.length; i++) {
79	      v = arr[i];
80	      if (typeof v !== "number" || !isFinite(v)) return null;
81	      out[i] = v;
82	    }
83	    return out;
84	  }
