import { readFileSync } from "node:fs";
import vm from "node:vm";

const html = readFileSync("index.html", "utf8");
const scripts = [...html.matchAll(/<script>([\s\S]*?)<\/script>/g)].map(m => m[1]);
console.log("script blocks:", scripts.length);

const ctx = { window: {}, THREE: {}, document: { getElementById: () => ({ style: {}, classList: { add(){}, toggle(){} }, appendChild(){}, addEventListener(){} }), title: "", createElement: () => ({ style:{}, classList:{add(){},toggle(){}}, appendChild(){}, setAttribute(){}, addEventListener(){} }), body: {} }, navigator: {}, matchMedia: () => ({matches:false}) };
ctx.window = ctx;
vm.createContext(ctx);

// Only syntax-check the data blocks (1,2,3,4 = manifest, geometry, volume, evidence)
for (let i = 0; i < 4; i++) {
  try {
    new vm.Script(scripts[i]);
    console.log(`block ${i}: OK`);
  } catch (e) {
    console.log(`block ${i}: SYNTAX ERROR: ${e.message}`);
  }
}

// Evaluate manifest+geometry+volume+evidence blocks for structural sanity
try {
  vm.runInContext(scripts[0] + "\n" + scripts[1] + "\n" + scripts[2] + "\n" + scripts[3], ctx);
  console.log("sample_id:", ctx.window.REVIEW_MANIFEST.sample_id);
  console.log("data_globals:", ctx.window.REVIEW_MANIFEST.data_globals);
  console.log("produced_from:", ctx.window.REVIEW_MANIFEST.produced_from);
  console.log("meshes keys:", Object.keys(ctx.window.REVIEW_GEOMETRY.meshes));
  console.log("REVIEW_VOLUME sentinel:", ctx.window.REVIEW_VOLUME);
  console.log("decisive:", ctx.window.REVIEW_EVIDENCE.decisive);
  console.log("landmarks:", ctx.window.REVIEW_EVIDENCE.landmarks);
  console.log("interpretation.flags:", ctx.window.REVIEW_EVIDENCE.interpretation.flags);
} catch (e) {
  console.log("EVAL ERROR:", e.message);
}

